import re

_BASE64_AFTER_MARKER_RE = re.compile(
    r'(base64,)[A-Za-z0-9+/=\r\n]+(?=(?:["\s]|$))',
    re.IGNORECASE,
)

def strip_after_base64_marker(text: str) -> str:
    """Mantém 'base64,' e remove o payload até aspas/espaço/fim."""
    if not isinstance(text, str):
        return text
    return _BASE64_AFTER_MARKER_RE.sub(r'\1', text)

items = _input.all()

for item in items:
    try:
        data = item["json"]
    except Exception:
        data = item  # fallback, caso venha direto

    for k, v in list(data.items()):
        if isinstance(v, str):
            data[k] = strip_after_base64_marker(v)

return items

