const tagsDict = {
  1: "Bug",
  2: "Pendente Requisitos",
  3: "MVP",
  4: "Front",
  5: "Back",
  6: "Design",
  7: "Produto",
  8: "Feature",
  9: "Infraestrutura",
  10: "QA",
  11: "Prioridade",
  12: "Reprovado",
  13: "Em Orçamento",
  14: "Retrabalho",
  15: "Computar",
  16: "Não Computar",
  17: "BI",
  18: "3",
  19: "2",
  20: "1",
  21: "irreproduzível"
};

return $input.all().map(item => {
  const tags = (item.json.tags || []).map(id => ({
    id,
    nome: tagsDict[id] || `Tag ${id} desconhecida`
  }));
  item.json.tags = tags;
  return item;
});

const output = [];

for (const item of $input.all()) {
  // Caminho até o array de similaridades
  const similaridades = item.json?.data?.resultado?.alertas_gerais?.[0]?.similaridade_titulo;

  if (Array.isArray(similaridades)) {
    // Para cada similaridade (cada objeto com cards + grau_de_similaridade)
    for (const sim of similaridades) {
      // Garante que cada saida seja um item completo
      output.push({
        json: {
          cards: sim.cards,
          grau_de_similaridade: sim.grau_de_similaridade
        }
      });
    }
  }
}

return output;

const mapaTipos = {
    "sem_titulo": 2, "sem_descricao": 3, "sem_responsaveis": 4, "sem_tags": 5, 
    "sem_data_criacao": 6, "sem_estimativa_esforco": 7, "sem_data_prevista": 8, 
    "sem_data_desejada": 9, "sem_pontos": 10, "sem_vinculo_projeto": 11, 
    "descricao_curta": 12, "sem_criterios_aceite": 13, "tags_pouco_descritivas": 14, 
    "data_prevista_antes_criacao": 15, "data_conclusao_antes_criacao": 16, 
    "card_antigo_sem_priorizacao": 17
};

const itemsDeSaida = [];

// Loop sobre todos os itens de entrada (cada card no Loop Over Items8)
for (const item of $input.all()) {
    
    // Acessa o objeto de alertas de validação.
    const alertasValidacao = item.json.alertas_validacao;
    
    // Obtém o ID do card original (chave de correspondência futura no Merge)
    const cardId = item.json.id; 
    
    // Verifica se o objeto de alertas existe
    if (typeof alertasValidacao === 'object' && alertasValidacao !== null) {

        // Itera sobre as chaves (os nomes dos alertas)
        for (const tipoAlerta in alertasValidacao) {
            
            // Verifica se a chave existe no objeto E no nosso mapa de IDs
            if (alertasValidacao.hasOwnProperty(tipoAlerta) && mapaTipos.hasOwnProperty(tipoAlerta)) {
                
                const statusAtivo = alertasValidacao[tipoAlerta];

                // Busca o ID do tipo de alerta
                const alertaTipoId = mapaTipos[tipoAlerta];

                // Cria um novo item para cada par chave-valor
                itemsDeSaida.push({
                    json: {
                        // IDs PRINCIPAIS PARA A INSERÇÃO
                        alerta_card_tipo_id: alertaTipoId,
                        ativo: statusAtivo, 
                        dados: JSON.stringify({ [tipoAlerta]: statusAtivo }),

                        // CHAVE DE CORRESPONDÊNCIA PARA O MERGE
                        card_referencia_id: cardId, 
                        tipo_alerta: tipoAlerta
                    }
                });
            }
        }
    }
}

return itemsDeSaida;

